INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_YN_FEM_PRI1', '무주택 본인 여부', 'user.isHomeOwner', 'EQUAL', 'false', 1, 'ELIGIBILITY', '신청자 본인이 무주택자여야 함 (주택공급에 관한 규칙 제53조 판정기준)', '신청자 본인이 주택을 소유하여 제외되었습니다.');
