INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI2', '소득 기준 50% 이하 가점', 'user.isIncomeUnder50', 'EQUAL', 'true|3', 0, 'SCORING', '소득수준이 해당 순위 소득 기준의 50% 이하인 경우 3점 가점 부여', '소득 50% 이하 가점 요건 미충족');
INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI2', '청약저축 가점 (24회 이상)', 'user.subscriptionCount', 'GTE', '24|3', 0, 'SCORING', '본인 명의 청약저축 납입 회차 24회 이상 시 3점 부여', '청약 24회 미만');
