INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI3', '무주택 본인 여부', 'user.isHomeOwner', 'EQUAL', 'false', 1, 'ELIGIBILITY', '신청자 본인이 무주택자여야 함 (주택공급에 관한 규칙 제53조 판정기준)', '신청자 본인이 주택을 소유하여 제외되었습니다.');
INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI3', '미혼 조건 검증', 'user.isMarried', 'EQUAL', 'false', 1, 'ELIGIBILITY', '공고일 현재 신청자가 미혼(현재 혼인 상태가 아님)일 것', '본 공고는 미혼자만 신청할 수 있습니다.');
INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI3', '서울 소재 대학교 학적 검증', 'user.schoolLocation', 'EQUAL', '서울', 1, 'ELIGIBILITY', '서울특별시 소재 대학교(전문대 포함) 재학 또는 입학/복학예정자', '본 기숙사는 서울특별시 소재 대학교 재학생만 신청할 수 있습니다.');
