INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI3', '졸업유예 및 수료자 배제 룰', 'user.isGraduatedOrSuspended', 'EQUAL', 'false', 1, 'ELIGIBILITY', '졸업유예(수료)자는 대학생 기준으로 인정하지 않음', '졸업유예(수료)자는 대학생 기준에 미달하여 제외됩니다.');
