INSERT INTO eligibility_rule (target_id, rule_name, field, operator, value, is_mandatory, rule_type, description, error_message) VALUES ('SH_2025_HOPE_HOUSING_01_JR_MAL_PRI3', '본인 단독 자산 검증 (행복주택 대학생 기준)', 'user.totalAsset', 'LTE', '104000000', 1, 'ELIGIBILITY', '본인 단독 총자산 1억 400만 원 이하 (2025년 2차 기준)', '본인 총자산이 기준 한도액(1.04억)을 초과하였습니다.');
